// PLANERINGS VY (startsidan)
// ═══════════════════════════════════════════════════════════════════════
const PlaneringsVy = ({blocks, appState, setAppState, setBlocks, onStartCoach, onVisaAvslutad, onRedigera, onOvningsbank, onVarderingar, onArbetssatt, onStatistik, onAdmin, onLogout, syncBadge, trupp, onRefreshTrupp, mvBlocks, setMvBlocks, kalevent=[], currentUser}) => {
  const [openBlock, setOpenBlock] = useState(blocks[0]?.id||1);
  const [visaAvslutade, setVisaAvslutade] = useState(false);
  const [showGenModal, setShowGenModal] = useState(false);
  const [genSkeden, setGenSkeden] = useState([]);
  const [lagTyp, setLagTyp] = useState("lag"); // "lag" | "mv"
  const [dragIdx, setDragIdx] = useState(null);
  const [dragOverIdx, setDragOverIdx] = useState(null);

  const getTranState = (bId,tNr) => appState[tranKey(bId,tNr)] || {};
  const setEvent = (bId,tNr,eid) => { const k=tranKey(bId,tNr); setAppState(p=>({...p,[k]:{...p[k],event:eid}})); };
  const isAvslutad = (bId,tNr) => !!getTranState(bId,tNr).avslutad;

  const aktiveraBlocks = lagTyp==="mv" ? mvBlocks : blocks;
  const totalt = aktiveraBlocks.reduce((s,b)=>s+b.trän.length,0);
  const avslutade = aktiveraBlocks.reduce((s,b)=>s+b.trän.filter(t=>isAvslutad(b.id,t.nr)).length,0);
  const koppladeEvent = aktiveraBlocks.reduce((s,b)=>s+b.trän.filter(t=>getTranState(b.id,t.nr).event).length,0);

  // Check if last block is complete
  const sistaBlock = aktiveraBlocks[aktiveraBlocks.length-1];
  const sistaBlockKlar = sistaBlock && sistaBlock.trän.every(t=>isAvslutad(sistaBlock.id,t.nr));

  const handleGenBlock = () => {
    if (lagTyp === "mv") {
      const nb = genMVBlock(mvBlocks);
      const newMv = [...mvBlocks, nb];
      setMvBlocks(newMv);
      setOpenBlock(nb.id);
    } else {
      const nb = genBlock(blocks, genSkeden.length > 0 ? genSkeden : null);
      const newBlocks = [...blocks, nb];
      setBlocks(newBlocks);
      setOpenBlock(nb.id);
    }
    setShowGenModal(false);
    setGenSkeden([]);
  };
  const toggleGenSkede = (s) => setGenSkeden(p => p.includes(s) ? p.filter(x=>x!==s) : [...p,s]);

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="sticky top-0 z-30 bg-white border-b border-gray-200 shadow-sm">
        <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between gap-3">
          <div className="flex items-center gap-2.5 min-w-0 flex-shrink-0">
            <img src={LOGO} alt="RIK" className="h-9 w-9 object-contain flex-shrink-0"/>
            <div className="min-w-0">
              <div className="text-gray-900 font-bold text-sm leading-tight whitespace-nowrap">Rynninge IK</div>
              <div className="text-amber-600 text-[10px] font-semibold tracking-wide whitespace-nowrap">P14–16</div>
            </div>
          </div>
          <div className="flex items-center gap-2">
            {/* Dropdown menu for secondary nav */}
            {(()=>{
              const [menuOpen, setMenuOpen] = React.useState(false);
              React.useEffect(()=>{
                if(!menuOpen) return;
                const close = ()=>setMenuOpen(false);
                document.addEventListener('click', close, {once:true});
                return ()=>document.removeEventListener('click', close);
              },[menuOpen]);
              return (
                <div className="relative">
                  <button onClick={e=>{e.stopPropagation();setMenuOpen(v=>!v);}}
                    className="flex items-center gap-1.5 text-xs font-bold bg-gray-100 hover:bg-gray-200 text-gray-900 border border-gray-200 px-3 py-2 rounded-xl transition-colors">
                    ☰ Meny
                  </button>
                  {menuOpen&&(
                    <div className="absolute right-0 top-full mt-1 bg-white border border-gray-200 rounded-2xl shadow-lg py-1.5 z-50 min-w-[160px]">
                      {[
                        [onOvningsbank, <><BookOpen className="h-3.5 w-3.5"/>Övningar</>],
                        [onVarderingar, <>⭐ Värderingar</>],
                        [onArbetssatt,  <>🧩 Arbetssätt</>],
                        [onStatistik,   <>📊 Statistik</>],
                      ].map(([fn,label],i)=>(
                        <button key={i} onClick={()=>{fn();setMenuOpen(false);}}
                          className="w-full flex items-center gap-2.5 px-4 py-2.5 text-xs font-semibold text-gray-700 hover:bg-gray-50 text-left">
                          {label}
                        </button>
                      ))}
                    </div>
                  )}
                </div>
              );
            })()}
            <button onClick={()=>setVisaAvslutade(v=>!v)} className={`flex items-center gap-1.5 text-xs font-bold px-3 py-2 rounded-xl border transition-colors ${visaAvslutade?"bg-amber-500 text-white border-amber-500":"bg-gray-100 text-gray-900 border-gray-200 hover:bg-gray-100"}`}>
              <Eye className="h-3.5 w-3.5"/>{visaAvslutade?"Dölj avslutade":"Visa avslutade"}
            </button>
            <button onClick={onRefreshTrupp} className="flex items-center gap-1.5 text-xs font-bold bg-gray-100 hover:bg-gray-100 text-gray-900 border border-gray-200 px-2.5 py-2 rounded-xl transition-colors" title="Uppdatera spelarlistan från laget.se">
              <RefreshCw className="h-3.5 w-3.5"/>
            </button>
            {(currentUser?.roll==='coach'||currentUser?.roll==='tranare')&&(
              <button onClick={onAdmin} className="text-xs font-bold bg-gray-100 hover:bg-gray-200 text-gray-700 border border-gray-200 px-2.5 py-2 rounded-xl" title="Användaradmin">
                👤
              </button>
            )}
            <button onClick={onLogout} className="text-xs font-medium text-gray-500 hover:text-gray-700 border border-gray-200 px-2.5 py-2 rounded-xl" title="Logga ut">
              ↩
            </button>
            {syncBadge}
          </div>
        </div>
      </header>

      <div className="max-w-4xl mx-auto px-4 py-5 space-y-3">
        {/* Progress */}
        <div className="bg-white rounded-2xl p-4 shadow-sm ring-1 ring-gray-200">
          <div className="flex items-center justify-between mb-2">
            <div className="text-sm font-black text-gray-700">Säsongsframsteg</div>
            <div className="text-sm font-bold text-gray-500">{avslutade}/{totalt} träningar</div>
          </div>
          <div className="h-3 bg-gray-50 rounded-full overflow-hidden">
            <div className="h-full rounded-full bg-amber-400 transition-all duration-500" style={{width:`${totalt>0?(avslutade/totalt)*100:0}%`}}/>
          </div>
          <div className="flex justify-between mt-2 text-[10px] text-gray-500 font-semibold">
            <span>{avslutade} avslutade</span>
            <span>{koppladeEvent} kopplade till kalender</span>
            <span>{totalt-avslutade} kvar</span>
          </div>
        </div>

        {/* Lagtyp toggle */}
        <div className="bg-white rounded-2xl p-1.5 shadow-sm ring-1 ring-gray-200 flex gap-1.5">
          <button onClick={()=>setLagTyp("lag")}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-black transition-all ${lagTyp==="lag"?"bg-white text-gray-900 shadow":"text-gray-500 hover:bg-gray-50"}`}>
            ⚽ Lagträning
          </button>
          <button onClick={()=>setLagTyp("mv")}
            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-xl text-sm font-black transition-all ${lagTyp==="mv"?"bg-violet-100 text-gray-900 shadow":"text-gray-500 hover:bg-gray-50"}`}>
            🧤 Målvaktsträning
          </button>
        </div>

        {/* Generera block-prompt */}
        {sistaBlockKlar&&(
          <div className="bg-green-50 border border-green-300 rounded-2xl p-4 flex items-center justify-between gap-3">
            <div>
              <div className="font-black text-green-800 text-sm">✅ {sistaBlock.titel} är klart!</div>
              <div className="text-xs text-green-700 mt-0.5">Dags att generera nästa träningsblock baserat på dina schemalagda träningstillfällen.</div>
            </div>
            <button onClick={()=>setShowGenModal(true)} className="flex items-center gap-1.5 bg-green-600 hover:bg-green-600 text-gray-900 px-4 py-2.5 rounded-xl text-sm font-black flex-shrink-0">
              <PlusCircle className="h-4 w-4"/>Nytt block
            </button>
          </div>
        )}

        {/* BLOCK */}
        {aktiveraBlocks.map((block, bi)=>{
          const isOpen=openBlock===block.id;
          const bc = (block.typ==="MV") ? MV_BLOCKFARG : BLOCKFARG[bi%BLOCKFARG.length];
          const blokAvslutade=block.trän.filter(t=>isAvslutad(block.id,t.nr)).length;
          const synliga=block.trän.filter(t=>visaAvslutade||!isAvslutad(block.id,t.nr));
          const period=blockPeriod(block,appState);

          return(
            <div key={block.id} className={`rounded-2xl shadow-sm overflow-hidden ${dragOverIdx===bi?"ring-2 ring-yellow-400":""}`}>
              {/* Single full-width colored header row */}
              <div className={`${bc} flex items-stretch`}
                onDragOver={e=>{e.preventDefault();setDragOverIdx(bi);}}
                onDrop={()=>{
                  if(dragIdx===null||dragIdx===bi) return;
                  const lst=[...aktiveraBlocks];
                  const [moved]=lst.splice(dragIdx,1);
                  lst.splice(bi,0,moved);
                  if(lagTyp==="mv") setMvBlocks(lst); else setBlocks(lst);
                  setDragIdx(null); setDragOverIdx(null);
                }}
                onDragEnd={()=>{setDragIdx(null);setDragOverIdx(null);}}>
                {/* Drag grip */}
                <div draggable onDragStart={()=>setDragIdx(bi)}
                  className="flex items-center px-2.5 cursor-grab active:cursor-grabbing select-none opacity-50 hover:opacity-100 transition-opacity flex-shrink-0"
                  title="Dra för att byta ordning">
                  <span className="text-gray-900 text-base leading-none">⠿</span>
                </div>
                {/* Title + meta — clickable */}
                <button onClick={()=>setOpenBlock(isOpen?0:block.id)}
                  className="flex-1 px-3 py-3 flex items-center gap-2 flex-wrap text-left hover:opacity-90 transition-opacity min-w-0">
                  <span className="font-black text-base leading-tight">{block.titel}</span>
                  <span className="text-xs bg-gray-100 px-2 py-0.5 rounded font-semibold whitespace-nowrap">{period}</span>
                  <span className="text-xs bg-gray-100 px-2 py-0.5 rounded font-semibold whitespace-nowrap">{block.vardeord}</span>
                  <span className="text-xs bg-gray-100 px-2 py-0.5 rounded whitespace-nowrap">{blokAvslutade}/{block.trän.length} klara</span>
                </button>
                {/* Actions */}
                <div className="flex items-center gap-1 px-2 flex-shrink-0">
                  {aktiveraBlocks.length > 1 && (
                    <button onClick={e=>{e.stopPropagation();if(window.confirm(`Ta bort "${block.titel}"?\nNärvaro och betyg för detta block raderas.`)){if(lagTyp==="mv"){setMvBlocks(prev=>prev.filter(b=>b.id!==block.id));}else{setBlocks(prev=>prev.filter(b=>b.id!==block.id));}}}}
                      className="p-1.5 rounded-lg hover:bg-red-500/40 transition-colors text-gray-900/70 hover:text-gray-900" title="Ta bort block">
                      <X className="h-4 w-4"/>
                    </button>
                  )}
                  <button onClick={()=>setOpenBlock(isOpen?0:block.id)} className="p-1.5 text-white/80 hover:text-white transition-colors">
                    {isOpen?<ChevronUp className="h-5 w-5"/>:<ChevronDown className="h-5 w-5"/>}
                  </button>
                </div>
              </div>

              {isOpen&&(
                <div className="bg-white p-3 space-y-2 ring-1 ring-gray-200 rounded-b-2xl">
                  {synliga.length===0&&(
                    <div className="text-center text-gray-500 py-6 text-sm">Alla träningar avslutade. <button onClick={()=>setVisaAvslutade(true)} className="text-blue-600 font-bold underline">Visa avslutade</button></div>
                  )}
                  {synliga.map(tran=>{
                    const ts=getTranState(block.id,tran.nr);
                    const avslutad=!!ts.avslutad;
                    const ev=KALEVENT.find(e=>e.id===ts.event);
                    const blaAntal=TRUPP.filter(s=>ts.narvaro?.[s.id]?.status==="bla").length;
                    const vitAntal=TRUPP.filter(s=>ts.narvaro?.[s.id]?.status==="vit").length;
                    const harNarv=blaAntal+vitAntal>0;

                    return(
                      <div key={tran.nr} className={`border rounded-xl overflow-hidden transition-all ${avslutad?"border-emerald-200 bg-emerald-50 opacity-80":"border-gray-200 bg-white hover:border-gray-300"}`}>
                        {/* Top row: dag + badges + actions */}
                        <div className="flex items-center justify-between gap-3 px-3 pt-3 pb-2">
                          <div className="flex items-center gap-2 min-w-0 flex-1 flex-wrap">
                            <div className="bg-gray-100 text-gray-700 text-[10px] font-bold px-2 py-1 rounded-lg flex-shrink-0 text-center leading-tight min-w-[32px]">
                              <div>B{bi+1}</div><div>T{tran.nr}</div>
                            </div>
                            {tran.skeden.map(s=><SkedeBadge key={s} id={s}/>)}
                            {avslutad&&<span className="text-[10px] bg-emerald-100 text-emerald-700 border border-emerald-300 px-1.5 py-0.5 rounded font-bold">✓ Genomförd</span>}
                          </div>
                          <div className="flex gap-1.5 flex-shrink-0">
                            {!avslutad&&(
                              <button onClick={()=>onRedigera(block,tran)} className="flex items-center gap-1 bg-gray-50 hover:bg-gray-100 text-gray-600 border border-gray-200 px-2.5 py-1.5 rounded-lg text-xs font-medium transition-colors">
                                <Edit3 className="h-3.5 w-3.5"/>Redigera
                              </button>
                            )}
                            {avslutad?(
                              <button onClick={()=>onVisaAvslutad(block,tran)} className="flex items-center gap-1.5 bg-emerald-100 hover:bg-emerald-200 text-emerald-800 border border-emerald-300 px-3 py-1.5 rounded-lg text-xs font-medium transition-colors">
                                <Eye className="h-3.5 w-3.5"/>Visa
                              </button>
                            ):(
                              <button onClick={()=>onStartCoach(block,tran)} className="flex items-center gap-1.5 bg-amber-500 hover:bg-amber-600 text-white px-3 py-1.5 rounded-lg text-xs font-semibold transition-colors">
                                <Play className="h-3.5 w-3.5"/>Starta
                              </button>
                            )}
                          </div>
                        </div>
                        {/* Syfte — full width */}
                        <div className="px-3 pb-2">
                          <p className="text-sm font-medium text-gray-900 leading-snug">{tran.syfte}</p>
                          <div className="flex items-center gap-3 mt-1.5 flex-wrap">
                            <span className="text-xs text-gray-400">{tran.delar.reduce((s,d)=>s+d.tid,0)} min · {tran.delar.length} delar</span>
                            {ev&&<span className="text-[10px] bg-blue-50 text-blue-700 border border-blue-200 px-2 py-0.5 rounded-full font-medium flex items-center gap-1"><Calendar className="h-3 w-3"/>{ev.label}</span>}
                            {harNarv&&<span className="text-[10px] text-gray-400 flex items-center gap-1">{blaAntal>0&&<span className="text-blue-500 font-semibold">🔵{blaAntal}</span>}{vitAntal>0&&<span className="text-gray-400 font-semibold ml-1">⚪{vitAntal}</span>}</span>}
                          </div>
                        </div>
                        {/* Principer */}
                        {tran.principer?.length>0&&(
                          <div className="px-3 pb-2 flex flex-wrap gap-1.5">
                            {tran.principer.map(p=><span key={p} className="text-[10px] bg-gray-100 text-gray-600 border border-gray-200 px-2 py-0.5 rounded-full">{p}</span>)}
                          </div>
                        )}
                        {/* Kalender */}
                        {!avslutad&&(
                          <div className="px-3 pb-3 flex items-center gap-2">
                            <Calendar className="h-3.5 w-3.5 text-gray-400 flex-shrink-0"/>
                            <select value={ts.event||""} onChange={e=>setEvent(block.id,tran.nr,e.target.value)}
                              className="text-xs border border-gray-200 rounded-lg px-2 py-1 bg-white text-gray-600 focus:outline-none focus:ring-1 focus:ring-amber-400 flex-1 min-w-0">
                              <option value="">Koppla till planerad träning…</option>
                              {kalevent
                                .filter(e => e.datum >= new Date().toISOString().slice(0,10))
                                .slice(0, 9)
                                .map(e=><option key={e.id} value={e.id}>{e.label}</option>)}
                            </select>
                          </div>
                        )}
                        <div className="px-3 pb-2 flex flex-wrap gap-1">
                          {tran.principer.slice(0,4).map(p=><span key={p} className="text-[10px] bg-gray-50 text-gray-600 border border-gray-200 px-1.5 py-0.5 rounded font-medium">{p}</span>)}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          );
        })}

        {/* Manuell generera block-knapp */}
        <button onClick={()=>setShowGenModal(true)} className="w-full flex items-center justify-center gap-2 border-2 border-dashed border-gray-300 text-gray-500 hover:border-blue-400 hover:text-blue-600 rounded-2xl py-4 text-sm font-bold transition-colors">
          <PlusCircle className="h-5 w-5"/>Generera nytt träningsblock
        </button>
      </div>

      {/* Generera block modal */}
      {showGenModal&&(
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
          <div className="bg-white rounded-2xl p-6 max-w-md w-full shadow-2xl">
            <div className="text-xl font-black text-slate-900 mb-1">Generera Block {blocks.length+1}</div>
            <p className="text-sm text-gray-500 mb-4">Välj vilket skeende blocket ska fokusera på. Varje träning får en förberedelseövning, färdighetsövning och spelövning.</p>
            <div className="text-xs font-black uppercase tracking-wider text-gray-500 mb-2">Fokus – välj ett eller flera skeenden</div>
            <div className="grid grid-cols-2 gap-2 mb-4">
              {[
                ["ANF","⚽","Anfallsspel","Speluppbyggnad, djupled, avslut"],
                ["FORS","🛡️","Försvarsspel","Press, täckning, förhindra avslut"],
                ["OMANF","⚡","Omst. → Anfall","Kontring, snabbt framåt"],
                ["OMFOR","🔄","Omst. → Försvar","Återerövring, kollektivt försvar"],
                ["MV","🧤","Målvaktsträning","Djupledsspel, inlägg, skott"],
                ["FYS","🏋️","Fysisk träning","Styrka, rörlighet, löpteknik"],
              ].map(([s,icon,label,sub])=>{
                const on=genSkeden.includes(s);
                return(
                  <button key={s} onClick={()=>toggleGenSkede(s)}
                    className={`flex items-start gap-2 p-3 rounded-xl border text-left transition-all ${on?"border-blue-200 bg-blue-50 ring-1 ring-blue-400":"border-gray-200 bg-gray-50 hover:border-blue-300"}`}>
                    <span className="text-xl flex-shrink-0">{icon}</span>
                    <div>
                      <div className={`text-xs font-black ${on?"text-blue-900":"text-gray-700"}`}>{label}</div>
                      <div className={`text-[10px] ${on?"text-blue-600":"text-gray-500"}`}>{sub}</div>
                    </div>
                    {on&&<span className="ml-auto text-blue-700">✓</span>}
                  </button>
                );
              })}
            </div>
            {genSkeden.length===0&&(
              <div className="text-xs text-amber-600 bg-amber-50 border border-amber-200 rounded-xl p-2.5 mb-4">
                Inget skeende valt — blocket genereras automatiskt baserat på SvFF:s progression.
              </div>
            )}
            {genSkeden.length>0&&(
              <div className="text-xs text-blue-700 bg-blue-50 border border-blue-200 rounded-xl p-2.5 mb-4">
                Block {blocks.length+1} fokuserar på: <strong>{genSkeden.join(" + ")}</strong>. Alla 6 träningar byggs med detta fokus, med 1–2 REP-övningar från föregående block.
              </div>
            )}
            <div className="flex gap-3">
              <button onClick={()=>{setShowGenModal(false);setGenSkeden([]);}} className="flex-1 border border-gray-200 px-4 py-2.5 rounded-xl text-sm font-bold text-gray-700 hover:bg-gray-50">Avbryt</button>
              <button onClick={handleGenBlock} className="flex-1 bg-white hover:bg-blue-50 text-gray-900 px-4 py-2.5 rounded-xl text-sm font-black flex items-center justify-center gap-2">
                <PlusCircle className="h-4 w-4"/>Generera block {blocks.length+1}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// ═══════════════════════════════════════════════════════════════════════
// ROOT APP – med Supabase-synk
// ═══════════════════════════════════════════════════════════════════════
export default function App() {
  const [currentUser, setCurrentUser] = useState(()=>{
    try { return JSON.parse(sessionStorage.getItem('_rik_user')||'null'); } catch { return null; }
  });
  const [appState, setAppState] = useState(() => lsGet("_state", {}));
  const [blocks,   setBlocks]   = useState(() => lsGet("_blocks", null) || GRUNDBLOCK);
  const [mvBlocks, setMvBlocks] = useState(() => lsGet("_mvblocks", null) || []);
  const [favs,     setFavs]     = useState(() => loadF());
  const [view,     setView]     = useState("plan");
  const [trupp,    setTrupp]    = useState(TRUPP);
  const [kalevent, setKalevent] = useState(() => {
    try { const s = lsGet("_kalevent"); return s?.length ? s : KALEVENT; } catch { return KALEVENT; }
  });
  const [syncStatus, setSyncStatus] = useState(SUPA_OK ? "idle" : "offline");
  const [activeBlock, setActiveBlock] = useState(null);
  const [activeTran,  setActiveTran]  = useState(null);
  const syncTimer = useRef(null);

  // ── Ladda från Supabase vid start ──────────────────────────────────
  useEffect(() => {
    if (!SUPA_OK) return;
    setSyncStatus("loading");
    Promise.all([
      supaGet("rik_kv", "state"),
      supaGet("rik_kv", "blocks"),
      supaGet("rik_kv", "mvblocks"),
    ]).then(([remoteState, remoteBlocks, remoteMvBlocks]) => {
      if (remoteState)  { setAppState(remoteState);     lsSet("_state", remoteState); }
      if (remoteBlocks) { setBlocks(remoteBlocks);       lsSet("_blocks", remoteBlocks); }
      if (remoteMvBlocks){ setMvBlocks(remoteMvBlocks); lsSet("_mvblocks", remoteMvBlocks); }
      setSyncStatus("synced");
    }).catch(() => setSyncStatus("offline"));
  }, []);

  // ── Synka till Supabase med debounce (500ms) ─────────────────────
  const syncAll = useCallback((newState, newBlocks, newMvBlocks) => {
    lsSet("_state",    newState);
    lsSet("_blocks",   newBlocks);
    lsSet("_mvblocks", newMvBlocks);
    if (!SUPA_OK) return;
    clearTimeout(syncTimer.current);
    setSyncStatus("saving");
    syncTimer.current = setTimeout(async () => {
      const [ok1, ok2, ok3] = await Promise.all([
        supaSet("rik_kv", "state",    newState),
        supaSet("rik_kv", "blocks",   newBlocks),
        supaSet("rik_kv", "mvblocks", newMvBlocks),
      ]);
      setSyncStatus(ok1 && ok2 && ok3 ? "synced" : "offline");
    }, 500);
  }, []);
  // Keep syncState alias for backward compat
  const syncState = (ns, nb) => syncAll(ns, nb, mvBlocks);

  const updateAppState = useCallback((newState) => {
    setAppState(newState);
    syncState(newState, blocks);
  }, [blocks, syncState]);

  const updateBlocks = useCallback((newBlocks) => {
    setBlocks(newBlocks);
    syncAll(appState, newBlocks, mvBlocks);
  }, [appState, mvBlocks, syncAll]);

  const updateMvBlocks = useCallback((newMvBlocks) => {
    setMvBlocks(newMvBlocks);
    syncAll(appState, blocks, newMvBlocks);
  }, [appState, blocks, syncAll]);

  const getTranState = (bId, tNr) => appState[tranKey(bId, tNr)] || {};
  const setTranState = (bId, tNr, upd) => {
    const k = tranKey(bId, tNr);
    const next = { ...appState, [k]: { ...appState[k], ...upd } };
    updateAppState(next);
  };

  const goHome = () => { setView("plan"); setActiveBlock(null); setActiveTran(null); };

  const handleStartCoach    = (b, t) => { setActiveBlock(b); setActiveTran(t); setView("coach");    window.scrollTo(0,0); };
  const handleVisaAvslutad  = (b, t) => { setActiveBlock(b); setActiveTran(t); setView("visa");     window.scrollTo(0,0); };
  const handleRedigera      = (b, t) => { setActiveBlock(b); setActiveTran(t); setView("redigera"); window.scrollTo(0,0); };
  const handleAvsluta = () => {
    setTranState(activeBlock.id, activeTran.nr, { avslutad:true, avslutadDatum:new Date().toISOString() });
    goHome();
  };

  const handleSparaRedigering = (nyaDelar) => {
    const newBlocks = blocks.map(b =>
      b.id !== activeBlock.id ? b : {
        ...b, trän: b.trän.map(t => t.nr !== activeTran.nr ? t : { ...t, delar: nyaDelar })
      }
    );
    updateBlocks(newBlocks);
    setView("plan");
  };

  // Sync-statusindikator
  const SyncBadge = () => {
    if (!SUPA_OK) return (
      <span className="flex items-center gap-1 text-[10px] text-gray-500 font-semibold">
        <WifiOff className="h-3 w-3"/>Lokal
      </span>
    );
    return (
      <span className={`flex items-center gap-1 text-[10px] font-semibold ${syncStatus==="synced"?"text-green-600":syncStatus==="saving"||syncStatus==="loading"?"text-amber-600":"text-red-400"}`}>
        {syncStatus==="saving"||syncStatus==="loading" ? <Loader2 className="h-3 w-3 animate-spin"/> : syncStatus==="synced" ? <Wifi className="h-3 w-3"/> : <WifiOff className="h-3 w-3"/>}
        {syncStatus==="synced"?"Synkad":syncStatus==="saving"?"Sparar…":syncStatus==="loading"?"Laddar…":"Offline"}
      </span>
    );
  };

  const resolvedBlock = activeBlock ? blocks.find(b=>b.id===activeBlock.id)||activeBlock : null;
  const resolvedTran  = (resolvedBlock && activeTran) ? (resolvedBlock.trän.find(t=>t.nr===activeTran.nr)||activeTran) : activeTran;

  const handleLogin = (user) => {
    sessionStorage.setItem('_rik_user', JSON.stringify(user));
    setCurrentUser(user);
  };
  const handleLogout = () => {
    sessionStorage.removeItem('_rik_user');
    setCurrentUser(null);
  };

  // ── Portal — ej inloggad ──
  if (!currentUser) return <PortalVy onLogin={handleLogin}/>;

  // ── Spelarvy ──
  if (currentUser.roll==='spelare') return (
    <SpelarVy
      currentUser={currentUser} blocks={blocks} mvBlocks={mvBlocks}
      appState={appState} trupp={trupp} onLogout={handleLogout}/>
  );

  // ── Admin (bara coacher) ──
  if (view==='admin') return (
    <AdminVy onBack={goHome} currentUser={currentUser}/>
  );

  if (view==="ovningar") return (
    <OvningsbankVy favs={favs} setFavs={f=>{setFavs(f);saveF(f);}} onBack={goHome} onVälj={null} väljLabel={null}/>
  );
  if (view==="statistik") return (
    <StatistikVy blocks={blocks} mvBlocks={mvBlocks} appState={appState} trupp={trupp} onBack={goHome}/>
  );
  if (view==="varderingar") return (
    <VarderingarVy onBack={goHome}/>
  );
  if (view==="arbetssatt") return (
    <ArbetssattVy onBack={goHome}/>
  );
  if (view==="redigera"&&resolvedBlock&&resolvedTran) return (
    <RedigeraVy block={resolvedBlock} tran={resolvedTran} onSpara={handleSparaRedigering} onBack={goHome}/>
  );
  if ((view==="coach"||view==="visa")&&resolvedBlock&&resolvedTran) return (
    <CoachMode
      tran={resolvedTran} block={resolvedBlock}
      tranState={getTranState(resolvedBlock.id, resolvedTran.nr)}
      onUpdateState={upd=>setTranState(resolvedBlock.id, resolvedTran.nr, upd)}
      onAvsluta={handleAvsluta} onOmstart={()=>{}}
      readOnly={view==="visa"} onHome={goHome}
      favs={favs}
      onFavToggle={f=>{setFavs(f);saveF(f);}}
    />
  );
  const handleRefreshTrupp = () => {
    const input = window.prompt(
      "Klistra in träningsdatum från laget.se (ett datum per rad, format ÅÅÅÅ-MM-DD HH:MM):\n\nExempel:\n2026-08-18 19:00\n2026-08-20 18:30\n2026-08-21 19:30\n\nLämna tomt för att bara återställa spelarlistan.",
      ""
    );
    if (input === null) return; // Avbryt

    let uppdateradKalendern = false;

    // Parse dates if provided
    const lines = input.split("\n").map(l => l.trim()).filter(Boolean);
    if (lines.length > 0) {
      const DAGNAMN = ["Söndag","Måndag","Tisdag","Onsdag","Torsdag","Fredag","Lördag"];
      const MÅNNAMN = ["jan","feb","mar","apr","maj","jun","jul","aug","sep","okt","nov","dec"];
      const parsed = [];
      for (const line of lines) {
        // Accept "YYYY-MM-DD HH:MM" or "YYYY-MM-DD"
        const m = line.match(/^(\d{4}-\d{2}-\d{2})(?:\s+(\d{2}:\d{2}))?/);
        if (!m) continue;
        const datum = m[1];
        const tid = m[2] || "00:00";
        const d = new Date(datum);
        const dag = DAGNAMN[d.getDay()];
        const måndag = d.getDate();
        const mån = MÅNNAMN[d.getMonth()];
        const label = `${dag.slice(0,3)} ${måndag} ${mån} · ${tid}`;
        parsed.push({ id: `e_${datum}_${tid.replace(":","")}_${Math.random().toString(36).slice(2,6)}`, datum, dag, tid, label });
      }
      if (parsed.length > 0) {
        // Save to Supabase via rik_kv
        syncAll(appState, blocks, mvBlocks, parsed);
        setKalevent(parsed);
        lsSet("_kalevent", parsed);
        uppdateradKalendern = true;
      }
    }

    // Always reset trupp
    setTrupp(TRUPP);
    lsSet("_trupp", TRUPP);

    if (uppdateradKalendern) {
      alert(`✓ Spelarlistan återställd\n✓ Kalender uppdaterad med ${lines.length} datum`);
    } else {
      alert("✓ Spelarlistan återställd");
    }
  };

  return (
    <PlaneringsVy
      blocks={blocks} appState={appState}
      setAppState={updateAppState} setBlocks={updateBlocks}
      onStartCoach={handleStartCoach} onVisaAvslutad={handleVisaAvslutad}
      onRedigera={handleRedigera} onOvningsbank={()=>setView("ovningar")}
      onVarderingar={()=>setView("varderingar")}
      onArbetssatt={()=>setView("arbetssatt")}
      onStatistik={()=>setView("statistik")}
      onAdmin={()=>setView("admin")}
      onLogout={handleLogout}
      currentUser={currentUser}
      syncBadge={<SyncBadge/>}
      mvBlocks={mvBlocks}
      setMvBlocks={updateMvBlocks}
      trupp={trupp}
      onRefreshTrupp={handleRefreshTrupp}
      kalevent={kalevent}
    />
  );
}
